import{_ as e,o,c as a,ai as i}from"./chunks/framework.BH_J6TYN.js";const g=JSON.parse('{"title":"¿Qué es SYNTIstudio?","description":"Página web profesional completa para cualquier tipo de negocio venezolano","frontmatter":{"title":"¿Qué es SYNTIstudio?","description":"Página web profesional completa para cualquier tipo de negocio venezolano"},"headers":[],"relativePath":"studio/que-es-syntistudio.md","filePath":"studio/que-es-syntistudio.md"}'),d={name:"studio/que-es-syntistudio.md"};function r(n,t,s,l,c,u){return o(),a("div",null,[...t[0]||(t[0]=[i('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>SYNTIstudio es el producto principal de SYNTIweb. Te da una <strong>página web profesional completa</strong> con productos, servicios, información de contacto, medios de pago, colores personalizados y más — todo administrable desde tu celular.</p><p>Es ideal para cualquier negocio que necesita presencia digital: barberías, clínicas, academias, consultoras, marcas personales, ferreterías, gimnasios, estudios de diseño, y más.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p>Para crear uno nuevo: <code>syntiweb.com/onboarding</code> → <strong>&quot;Presencia Web Completa&quot;</strong> → Asistente de 5 pasos.</p><p>Una vez creado, tu página vive en <code>tunegocio.syntiweb.com</code> y tu panel se activa con <strong>Alt+S</strong> (escritorio) o manteniendo presionado el logo 3 segundos (móvil).</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Página completa</strong> con secciones configurables (hero, productos, servicios, contacto, etc.)</li><li><strong>Hasta 11 secciones</strong> dependiendo del plan</li><li><strong>Panel de administración flotante</strong> con 7 tabs para editar todo</li><li><strong>QR descargable</strong> para imprimir en tu local</li><li><strong>Tasa BCV automática</strong> — precios en REF con equivalente en bolívares</li><li><strong>30+ paletas de color</strong> organizadas por industria</li><li><strong>Botón WhatsApp</strong> visible en toda la página</li><li><strong>Indicador de horario</strong> — muestra si tu negocio está abierto o cerrado</li><li><strong>Imágenes optimizadas</strong> — se convierten automáticamente a WebP (máx 800px)</li></ul><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No procesa pagos — solo muestra qué métodos aceptas</li><li>No tiene carrito de compras (para eso está SYNTIcat)</li><li>No tiene menú de comida tipo restaurante (para eso está SYNTIfood)</li><li>No envía emails a tus clientes</li><li>No tiene blog ni sistema de publicaciones</li><li>No tiene login para clientes — tu página es pública</li><li>No rastrea inventario ni stock</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad (REF 99/año)</th><th>Crecimiento (REF 149/año)</th><th>Visión (REF 199/año)</th></tr></thead><tbody><tr><td>Productos</td><td>20</td><td>50</td><td>Ilimitados</td></tr><tr><td>Servicios</td><td>3</td><td>6</td><td>9</td></tr><tr><td>Secciones landing</td><td>7 básicas</td><td>+ Acerca de, Testimonios</td><td>+ FAQ, Sucursales</td></tr><tr><td>Paletas de color</td><td>10</td><td>17</td><td>17 + personalizada</td></tr><tr><td>WhatsApp</td><td>1 línea</td><td>2 líneas</td><td>Ilimitadas</td></tr><tr><td>Redes sociales</td><td>2</td><td>4</td><td>Ilimitadas</td></tr><tr><td>Medios de pago</td><td>Solo Pago Móvil + Efectivo</td><td>18 métodos</td><td>18 métodos + por sucursal</td></tr><tr><td>Google Maps</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>SEO avanzado</td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table><h2 id="secciones-de-la-landing" tabindex="-1">Secciones de la landing <a class="header-anchor" href="#secciones-de-la-landing" aria-label="Permalink to &quot;Secciones de la landing&quot;">​</a></h2><p>Tu página tiene secciones que puedes activar/desactivar y reordenar desde el panel:</p><table tabindex="0"><thead><tr><th>Sección</th><th>Descripción</th><th>Plan mínimo</th></tr></thead><tbody><tr><td><strong>Hero</strong></td><td>Portada con título, subtítulo, imagen y botón de WhatsApp</td><td>Oportunidad</td></tr><tr><td><strong>Productos</strong></td><td>Grid de productos con foto, nombre, precio y badge</td><td>Oportunidad</td></tr><tr><td><strong>Servicios</strong></td><td>Tarjetas de servicios con ícono/imagen y descripción</td><td>Oportunidad</td></tr><tr><td><strong>Contacto</strong></td><td>Info de contacto: teléfono, email, dirección, horario</td><td>Oportunidad</td></tr><tr><td><strong>Medios de Pago</strong></td><td>Chips informativos de métodos de pago aceptados</td><td>Oportunidad</td></tr><tr><td><strong>Llamado a Acción (CTA)</strong></td><td>Banda con mensaje y botón para contactarte</td><td>Oportunidad</td></tr><tr><td><strong>Footer</strong></td><td>Pie de página con links, redes sociales y branding</td><td>Oportunidad</td></tr><tr><td><strong>Acerca de</strong></td><td>Sección &quot;sobre nosotros&quot; con imagen y texto</td><td>Crecimiento</td></tr><tr><td><strong>Testimonios</strong></td><td>Carrusel de testimonios de clientes</td><td>Crecimiento</td></tr><tr><td><strong>FAQ</strong></td><td>Preguntas frecuentes en formato acordeón</td><td>Visión</td></tr><tr><td><strong>Sucursales</strong></td><td>Tarjetas con ubicación, horario y WhatsApp por sucursal</td><td>Visión</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-corte-estilo-—-barberia-en-san-cristobal" tabindex="-1">Caso: &quot;Corte &amp; Estilo&quot; — Barbería en San Cristóbal <a class="header-anchor" href="#caso-corte-estilo-—-barberia-en-san-cristobal" aria-label="Permalink to &quot;Caso: &quot;Corte &amp; Estilo&quot; — Barbería en San Cristóbal&quot;">​</a></h3><p>Juan tiene una barbería. Necesita que sus clientes lo encuentren en Google y vean sus servicios.</p><ol><li>Entra a <code>syntiweb.com/onboarding</code> → elige <strong>Presencia Web Completa</strong></li><li>Completa el asistente: &quot;Corte &amp; Estilo&quot;, tipo &quot;Belleza/Estética&quot;, ciudad &quot;San Cristóbal&quot;</li><li>Agrega eslogan: <em>&quot;Tu mejor versión empieza aquí&quot;</em></li><li>Elige plan <strong>Oportunidad</strong> (REF 99/año) y subdominio <code>corteyestilo</code></li><li>Su página queda en <code>corteyestilo.syntiweb.com</code></li><li>Desde el panel agrega: <ul><li>3 servicios: Corte clásico, Barba, Combo</li><li>5 productos: Cera, Gel, Shampoo, Aceite de barba, Tónico</li><li>Activa Pago Móvil y Efectivo como medios de pago</li></ul></li><li>Descarga el QR y lo pega en la puerta de la barbería</li></ol><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/asistente-configuracion.html">Asistente de configuración</a> — Los 5 pasos del wizard</li><li><a href="/studio/panel-administracion.html">Panel de administración</a> — Los 7 tabs del dashboard</li><li><a href="/shared/cuenta-y-planes.html">Planes y precios</a> — Compara todos los planes</li></ul>',21)])])}const m=e(d,[["render",r]]);export{g as __pageData,m as default};
